// Generic transactional email sender. Validates inputs + composes the
// Postmark API payload. Called by auth flows + Stripe flows + the agent
// daily summary generator. Authentication is via internal-only secret
// (req body contains { internal_secret, template, to, vars, reply_to? }) —
// the secret is set in n8n env as INTERNAL_EMAIL_SECRET. This workflow is
// not exposed to public callers; only other workflows on the same n8n
// instance reach it.
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) {
  return { json: { _unauthorized: true, error: 'internal secret required' } };
}
const tpl = body.template;
const to = body.to;
if (!tpl || !to) {
  return { json: { _empty: true, error: 'template and to are required' } };
}
const vars = body.vars || {};
const replyTo = body.reply_to || 'support@crystallux.org';

// Map our template ids to Postmark TemplateAlias values. Mary creates
// the templates in Postmark dashboard with the same alias values.
const aliasMap = {
  'magic-link':           'magic-link',
  'password-reset':       'password-reset',
  'welcome':              'welcome',
  'subscription-active':  'subscription-active',
  'subscription-past-due':'subscription-past-due',
  'subscription-canceled':'subscription-canceled',
  'invoice-receipt':      'invoice-receipt',
  'lead-meeting-booked':  'lead-meeting-booked',
  'agent-daily-summary':  'agent-daily-summary'
};
const templateAlias = aliasMap[tpl];
if (!templateAlias) {
  return { json: { _empty: true, error: 'unknown template: ' + tpl } };
}

// Universal multi-vertical: merge sensible defaults so every template can
// reference {{vertical}} / {{brand}} without exploding when caller forgets.
const tplVars = Object.assign({
  brand: 'Crystallux',
  brand_color: '#7C3AED',
  brand_url: 'https://crystallux.org',
  support_email: 'support@crystallux.org',
  vertical: 'service-industry'
}, vars);

return { json: {
  _authorized: true,
  postmark_payload: {
    From: 'Crystallux <hello@crystallux.org>',
    To: to,
    ReplyTo: replyTo,
    TemplateAlias: templateAlias,
    TemplateModel: tplVars,
    MessageStream: 'outbound'
  },
  template_alias: templateAlias,
  to: to
} };
